class Playground {
    async run(inputs) {
        const startNode = inputs[0] || '1';

        const nodes = [
            { id: '1', val: 1 },
            { id: '2', val: 2 },
            { id: '3', val: 3 },
            { id: '4', val: 4 },
            { id: '5', val: 5 },
            { id: '6', val: 6 }
        ];
        const edges = [
            { source: '1', target: '2', isDirected: false },
            { source: '1', target: '3', isDirected: false },
            { source: '2', target: '4', isDirected: false },
            { source: '3', target: '4', isDirected: false },
            { source: '5', target: '6', isDirected: false }
        ];

        this.graph.init(nodes, edges);
        this.visited.init([]);
        this.queue.init([]);
        this.stack.init([]);
        await this.await();

        const allNodes = nodes.map(n => n.id);

        // BFS
        this.log('Starting BFS Traversal...');
        const bfsVisited = new Set();

        // Try start node first, then others if disconnected
        const bfsOrder = [startNode, ...allNodes.filter(n => n !== startNode)];

        for (const node of bfsOrder) {
            if (bfsVisited.has(node)) continue;

            this.log('Component BFS from ' + node);
            const q = [node];
            bfsVisited.add(node);
            this.queue.enqueue(node);
            this.visited.push(node);
            this.graph.highlightNode(node, '#10b981');
            await this.await();

            while (q.length > 0) {
                const curr = q.shift();
                this.queue.dequeue();
                this.log('Visiting ' + curr);
                this.graph.highlightNode(curr, '#ec4899');
                await this.await();

                const neighbors = this.graph.getNeighbors(curr);
                for (const neighbor of neighbors) {
                    if (!bfsVisited.has(neighbor.node)) {
                        bfsVisited.add(neighbor.node);
                        q.push(neighbor.node);
                        this.queue.enqueue(neighbor.node);
                        this.visited.push(neighbor.node);
                        this.graph.highlightNode(neighbor.node, '#f59e0b');
                        this.graph.highlightEdge(curr, neighbor.node, '#f59e0b');
                        this.log('Found neighbor ' + neighbor.node);
                        await this.await();
                    }
                }
                this.graph.highlightNode(curr, '#10b981');
            }
        }

        this.log('BFS Complete.');
        await this.await();

        // DFS
        this.log('Resetting for DFS Traversal...');
        this.graph.clearHighlights();
        this.visited.init([]);
        this.stack.init([]);
        await this.await();

        const dfsVisited = new Set();
        const dfs = async (node) => {
            dfsVisited.add(node);
            this.visited.push(node);
            this.stack.push(node);
            this.graph.highlightNode(node, '#ec4899');
            this.log('Visiting ' + node);
            await this.await();

            const neighbors = this.graph.getNeighbors(node);
            for (const neighbor of neighbors) {
                if (!dfsVisited.has(neighbor.node)) {
                    this.graph.highlightEdge(node, neighbor.node, '#f59e0b');
                    await dfs(neighbor.node);
                    this.graph.highlightEdge(node, neighbor.node, '#10b981');
                }
            }
            this.stack.pop();
            this.graph.highlightNode(node, '#10b981');
        };

        const dfsOrder = [startNode, ...allNodes.filter(n => n !== startNode)];
        for (const node of dfsOrder) {
            if (!dfsVisited.has(node)) {
                this.log('Component DFS from ' + node);
                await dfs(node);
            }
        }

        this.log('DFS Complete.');
    }
}
